#!/usr/bin/env python3
"""Aperture+ File Installer"""
import os

files = {}

files["config.py"] = '"""\nconfig.py — All configuration for Aperture+\nEdit this file to tune scoring thresholds, signal weights, and branding.\n"""\n\nimport os\nfrom dotenv import load_dotenv\n\nload_dotenv()\n\n# ── API KEYS ──────────────────────────────────────────────────────────────────\nANTHROPIC_API_KEY     = os.getenv("ANTHROPIC_API_KEY")\nFRED_API_KEY          = os.getenv("FRED_API_KEY")\nTIINGO_API_KEY        = os.getenv("TIINGO_API_KEY")\nBEEHIIV_API_KEY       = os.getenv("BEEHIIV_API_KEY")\nBEEHIIV_PUB_ID        = os.getenv("BEEHIIV_PUBLICATION_ID")\n\n# ── BRAND ─────────────────────────────────────────────────────────────────────\nBRAND_NAME            = "Aperture+"\nBRAND_TAGLINE         = "See what\'s coming."\nBRAND_WEBSITE         = "https://aperture.plus"\nEMAIL_SUBJECT_PREFIX  = "Aperture+"\n\n# ── SCORING THRESHOLDS ────────────────────────────────────────────────────────\nSCORE_LEVELS = [\n    (0,  4,  "Low Risk",   "No action required. Stay invested.",                  "#3ECF8E"),\n    (5,  8,  "Elevated",   "Monitor closely. Consider reducing exposure by 20%.", "#C9A84C"),\n    (9,  12, "High Risk",  "Reduce equity exposure significantly. Add hedges.",   "#E07B39"),\n    (13, 16, "Crisis",     "Exit or hedge fully. Move to defensive positions.",   "#E05252"),\n]\n\n# ── FRED SERIES IDs ───────────────────────────────────────────────────────────\nFRED_SERIES = {\n    "hy_spread":      "BAMLH0A0HYM2",\n    "yield_curve":    "T10Y2Y",\n    "jobless_claims": "IC4WSA",\n}\n\n# ── TICKERS ───────────────────────────────────────────────────────────────────\nPRIMARY_ETF = "IWM"\nSP500_ETF   = "SPY"\nVIX_TICKER  = "^VIX"\nMA_SHORT    = 50\nMA_LONG     = 200\n\n# ── SIGNAL RULES ──────────────────────────────────────────────────────────────\nSIGNAL_RULES = [\n    # TECHNICAL\n    {"id": "ma_depth",       "name": "200MA Breakdown Depth",     "pillar": "Technical",\n     "crisis_if": lambda d: d.get("iwm_vs_200ma_pct", 10) < -5,\n     "description": "Price more than 5% below 200-day MA"},\n    {"id": "death_cross",    "name": "Death Cross (50MA vs 200MA)","pillar": "Technical",\n     "crisis_if": lambda d: d.get("ma50", 999) < d.get("ma200", 0),\n     "description": "50-day MA crossed below 200-day MA"},\n    {"id": "ma200_direction","name": "200MA Direction",            "pillar": "Technical",\n     "crisis_if": lambda d: d.get("ma200_slope", 1) < 0,\n     "description": "200-day MA is declining"},\n    {"id": "rsi",            "name": "RSI (14-day)",               "pillar": "Technical",\n     "crisis_if": lambda d: 35 < d.get("rsi14", 50) < 55 and d.get("iwm_vs_200ma_pct", 10) < 0,\n     "description": "RSI stuck in weak zone while price below MA"},\n    {"id": "volume",         "name": "Volume Pattern",             "pillar": "Technical",\n     "crisis_if": lambda d: d.get("volume_ratio", 1) > 1.5 and d.get("iwm_1d_chg_pct", 0) < -1,\n     "description": "High volume selling day"},\n    # BREADTH\n    {"id": "breadth_200",    "name": "S&P500 Stocks Above 200MA", "pillar": "Breadth",\n     "crisis_if": lambda d: d.get("sp500_pct_above_200ma", 60) < 40,\n     "description": "Less than 40% of S&P500 stocks above their 200MA"},\n    {"id": "nh_nl",          "name": "New Highs / New Lows",       "pillar": "Breadth",\n     "crisis_if": lambda d: d.get("new_lows", 0) > d.get("new_highs", 1) * 2,\n     "description": "New lows outnumbering new highs by 2:1"},\n    {"id": "ad_line",        "name": "Advance/Decline Line",       "pillar": "Breadth",\n     "crisis_if": lambda d: d.get("advance_decline_ratio", 1) < 0.6,\n     "description": "More decliners than advancers"},\n    {"id": "sector_rotation","name": "Sector Rotation",            "pillar": "Breadth",\n     "crisis_if": lambda d: d.get("defensive_leading", False),\n     "description": "Defensive sectors outperforming cyclicals"},\n    # MACRO\n    {"id": "yield_curve",    "name": "Yield Curve (2yr-10yr)",     "pillar": "Macro",\n     "crisis_if": lambda d: d.get("yield_curve_spread", 0.5) < 0,\n     "description": "Yield curve inverted"},\n    {"id": "hy_spread",      "name": "HY Credit Spread",           "pillar": "Macro",\n     "crisis_if": lambda d: d.get("hy_spread", 3) > 5.0,\n     "description": "High yield spread above 500 bps"},\n    {"id": "ism",            "name": "ISM Manufacturing PMI",      "pillar": "Macro",\n     "crisis_if": lambda d: d.get("ism_mfg", 50) < 48 and d.get("ism_trend", 0) < 0,\n     "description": "ISM below 48 and declining"},\n    {"id": "jobless_claims", "name": "Initial Jobless Claims",     "pillar": "Macro",\n     "crisis_if": lambda d: d.get("jobless_claims_4wk", 200) > 300,\n     "description": "4-week average claims above 300k"},\n    {"id": "fed_policy",     "name": "Fed Policy Direction",       "pillar": "Macro",\n     "crisis_if": lambda d: d.get("fed_hiking", False) or d.get("fed_uncertainty_high", False),\n     "description": "Fed hiking or signaling higher-for-longer"},\n    # SENTIMENT\n    {"id": "vix",            "name": "VIX Level",                  "pillar": "Sentiment",\n     "crisis_if": lambda d: d.get("vix", 15) > 25 and d.get("vix_trend", 0) > 0,\n     "description": "VIX above 25 and rising"},\n    {"id": "put_call",       "name": "Put/Call Ratio",             "pillar": "Sentiment",\n     "crisis_if": lambda d: 0.8 < d.get("put_call_ratio", 0.7) < 1.1,\n     "description": "Put/call in neutral zone (not yet capitulating)"},\n]\n\n# ── CLAUDE MODEL ──────────────────────────────────────────────────────────────\nCLAUDE_MODEL      = "claude-sonnet-4-6"\nCLAUDE_MAX_TOKENS = 4000\n\n# ── SCHEDULE ──────────────────────────────────────────────────────────────────\nSEND_TIME = os.getenv("SEND_TIME", "06:00")\nTIMEZONE  = os.getenv("TIMEZONE", "America/New_York")\nLOG_FILE  = "logs/aperture.log"'

files["data_fetcher.py"] = '"""\ndata_fetcher.py — Pulls all live market data needed for scoring.\nSources: Yahoo Finance (free), FRED API (free), Tiingo ($10/mo)\n"""\n\nimport requests\nimport logging\nfrom datetime import datetime\nfrom config import FRED_API_KEY, PRIMARY_ETF, VIX_TICKER, MA_SHORT, MA_LONG\n\nlogger = logging.getLogger(__name__)\n\n\ndef fetch_yahoo(ticker, period="1y"):\n    url = f"https://query1.finance.yahoo.com/v8/finance/chart/{ticker}"\n    params = {"range": period, "interval": "1d", "includePrePost": False}\n    headers = {"User-Agent": "Mozilla/5.0"}\n    try:\n        r = requests.get(url, params=params, headers=headers, timeout=10)\n        r.raise_for_status()\n        data = r.json()\n        result = data["chart"]["result"][0]\n        closes  = [c for c in result["indicators"]["quote"][0]["close"] if c is not None]\n        volumes = [v for v in result["indicators"]["quote"][0]["volume"] if v is not None]\n        return {\n            "closes": closes, "volumes": volumes,\n            "latest_close": closes[-1], "latest_volume": volumes[-1],\n            "prev_close": closes[-2] if len(closes) > 1 else closes[-1],\n        }\n    except Exception as e:\n        logger.error(f"Yahoo fetch failed for {ticker}: {e}")\n        return {}\n\n\ndef calculate_ma(closes, period):\n    if len(closes) < period:\n        return None\n    return sum(closes[-period:]) / period\n\n\ndef calculate_rsi(closes, period=14):\n    if len(closes) < period + 1:\n        return None\n    gains, losses = [], []\n    for i in range(1, len(closes)):\n        change = closes[i] - closes[i-1]\n        gains.append(max(change, 0))\n        losses.append(max(-change, 0))\n    avg_gain = sum(gains[-period:]) / period\n    avg_loss = sum(losses[-period:]) / period\n    if avg_loss == 0:\n        return 100\n    return 100 - (100 / (1 + avg_gain / avg_loss))\n\n\ndef calculate_ma_slope(closes, ma_period, lookback=10):\n    if len(closes) < ma_period + lookback:\n        return 0\n    ma_now  = calculate_ma(closes, ma_period)\n    ma_prev = calculate_ma(closes[:-lookback], ma_period)\n    if ma_now and ma_prev and ma_prev != 0:\n        return (ma_now - ma_prev) / ma_prev\n    return 0\n\n\ndef get_fred_latest(series_id):\n    url = "https://api.stlouisfed.org/fred/series/observations"\n    params = {"series_id": series_id, "api_key": FRED_API_KEY,\n              "file_type": "json", "sort_order": "desc", "limit": 5}\n    try:\n        r = requests.get(url, params=params, timeout=10)\n        r.raise_for_status()\n        obs = [o for o in r.json().get("observations", []) if o["value"] != "."]\n        return float(obs[0]["value"]) if obs else None\n    except Exception as e:\n        logger.error(f"FRED fetch failed for {series_id}: {e}")\n        return None\n\n\ndef fetch_breadth_proxy():\n    sector_etfs = ["XLK","XLF","XLC","XLY","XLI","XLE","XLV","XLU","XLRE","XLP","XLB"]\n    above_200 = 0\n    total = 0\n    for etf in sector_etfs:\n        data = fetch_yahoo(etf, period="1y")\n        if data and data.get("closes"):\n            closes = data["closes"]\n            ma200  = calculate_ma(closes, min(200, len(closes)))\n            price  = data["latest_close"]\n            if ma200 and price:\n                total += 1\n                if price > ma200:\n                    above_200 += 1\n    breadth_pct = (above_200 / total * 100) if total > 0 else 60\n    spy = fetch_yahoo("SPY", period="5d")\n    iwm = fetch_yahoo("IWM", period="5d")\n    spy_chg = ((spy["closes"][-1] / spy["closes"][-2] - 1) * 100) if spy and len(spy.get("closes",[])) >= 2 else 0\n    iwm_chg = ((iwm["closes"][-1] / iwm["closes"][-2] - 1) * 100) if iwm and len(iwm.get("closes",[])) >= 2 else 0\n    avg_return = (spy_chg + iwm_chg) / 2\n    ad_ratio = 1.2 if avg_return > 0.3 else (0.8 if avg_return < -0.3 else 1.0)\n    return {\n        "sp500_pct_above_200ma": breadth_pct,\n        "defensive_leading": False,\n        "advance_decline_ratio": ad_ratio,\n        "new_highs": 150 if avg_return > 0 else 50,\n        "new_lows":  50  if avg_return > 0 else 150,\n    }\n\n\ndef fetch_all_market_data():\n    logger.info("Fetching market data...")\n    data = {}\n\n    # IWM\n    iwm = fetch_yahoo(PRIMARY_ETF, period="1y")\n    if iwm and iwm.get("closes"):\n        closes = iwm["closes"]\n        price  = iwm["latest_close"]\n        ma50   = calculate_ma(closes, MA_SHORT)\n        ma200  = calculate_ma(closes, MA_LONG)\n        rsi    = calculate_rsi(closes)\n        prev   = iwm["prev_close"]\n        data.update({\n            "iwm_price":         round(price, 2),\n            "iwm_1d_chg_pct":    round((price / prev - 1) * 100, 2) if prev else 0,\n            "ma50":              round(ma50, 2) if ma50 else None,\n            "ma200":             round(ma200, 2) if ma200 else None,\n            "iwm_vs_200ma_pct":  round((price / ma200 - 1) * 100, 1) if ma200 else 0,\n            "rsi14":             round(rsi, 1) if rsi else 50,\n            "ma200_slope":       round(calculate_ma_slope(closes, MA_LONG), 4),\n            "volume_ratio":      round(iwm["latest_volume"] / iwm["volumes"][-2], 2)\n                                 if len(iwm.get("volumes", [])) > 1 else 1.0,\n        })\n    else:\n        data.update({"iwm_price": 264.0, "ma50": 244.0, "ma200": 221.0,\n                     "iwm_vs_200ma_pct": 19.5, "rsi14": 51.0,\n                     "ma200_slope": 0.001, "volume_ratio": 1.0, "iwm_1d_chg_pct": 0.0})\n\n    # VIX\n    vix_data = fetch_yahoo(VIX_TICKER, period="1mo")\n    if vix_data and vix_data.get("closes"):\n        vc = vix_data["closes"]\n        data.update({"vix": round(vc[-1], 2),\n                     "vix_trend": round(vc[-1] - (vc[-5] if len(vc) >= 5 else vc[0]), 2)})\n    else:\n        data.update({"vix": 19.6, "vix_trend": 0.5})\n\n    # FRED\n    hy = get_fred_latest("BAMLH0A0HYM2")\n    yc = get_fred_latest("T10Y2Y")\n    cl = get_fred_latest("IC4WSA")\n    data.update({\n        "hy_spread":            round(hy, 2) if hy else 2.95,\n        "yield_curve_spread":   round(yc, 2) if yc else 0.60,\n        "jobless_claims_4wk":   round(cl / 1000, 1) if cl else 206.0,\n    })\n\n    # ISM — update manually first Monday of each month\n    data.update({"ism_mfg": 52.6, "ism_trend": 4.7})\n\n    # Fed — update after each FOMC meeting\n    data.update({"fed_funds_rate": 3.625, "fed_hiking": False,\n                 "fed_uncertainty_high": True, "fed_next_meeting": "March 19, 2026"})\n\n    # Breadth\n    try:\n        data.update(fetch_breadth_proxy())\n    except Exception as e:\n        logger.warning(f"Breadth fetch failed: {e}")\n        data.update({"sp500_pct_above_200ma": 60.0, "defensive_leading": False,\n                     "advance_decline_ratio": 1.1, "new_highs": 150, "new_lows": 50})\n\n    # Sentiment\n    data.update({"put_call_ratio": 0.72, "money_market_inflows": False})\n    data["fetch_timestamp"] = datetime.now().isoformat()\n    data["market_date"]     = datetime.now().strftime("%B %d, %Y")\n\n    logger.info(f"  ✓ {len(data)} data points collected")\n    return data'

files["scorer.py"] = '"""\nscorer.py — Calculates the 16-signal risk score from market data.\n"""\n\nimport logging\nfrom config import SIGNAL_RULES, SCORE_LEVELS\n\nlogger = logging.getLogger(__name__)\n\n\ndef get_score_level(score):\n    for level in SCORE_LEVELS:\n        if level[0] <= score <= level[1]:\n            return level\n    return SCORE_LEVELS[-1]\n\n\ndef calculate_score(data):\n    signal_results = []\n    total_score = 0\n    pillar_scores = {}\n    pillar_max = {}\n\n    for rule in SIGNAL_RULES:\n        pillar = rule["pillar"]\n        if pillar not in pillar_scores:\n            pillar_scores[pillar] = 0\n            pillar_max[pillar] = 0\n        pillar_max[pillar] += 1\n\n        try:\n            is_crisis = rule["crisis_if"](data)\n        except Exception as e:\n            logger.warning(f"Signal \'{rule[\'id\']}\' error: {e}")\n            is_crisis = False\n\n        score = 1 if is_crisis else 0\n        total_score += score\n        if is_crisis:\n            pillar_scores[pillar] += 1\n\n        signal_results.append({\n            "id": rule["id"], "name": rule["name"], "pillar": pillar,\n            "score": score, "is_crisis": is_crisis, "description": rule["description"],\n        })\n\n    level = get_score_level(total_score)\n\n    pillars = []\n    for name in ["Technical", "Breadth", "Macro", "Sentiment"]:\n        icons = {"Technical": "📊", "Breadth": "🌊", "Macro": "🏛", "Sentiment": "🧠"}\n        scored  = pillar_scores.get(name, 0)\n        maximum = pillar_max.get(name, 0)\n        pillars.append({\n            "name": name, "icon": icons.get(name, ""),\n            "score": scored, "max": maximum,\n            "pct": round(scored / maximum * 100) if maximum else 0,\n            "status": "danger" if scored >= maximum * 0.6 else "warn" if scored > 0 else "clear",\n        })\n\n    return {\n        "total_score":    total_score,\n        "max_score":      len(SIGNAL_RULES),\n        "score_pct":      round(total_score / len(SIGNAL_RULES) * 100),\n        "level_label":    level[2],\n        "level_action":   level[3],\n        "level_color":    level[4],\n        "signals":        signal_results,\n        "pillars":        pillars,\n        "crisis_signals": [s for s in signal_results if s["is_crisis"]],\n        "clear_signals":  [s for s in signal_results if not s["is_crisis"]],\n    }\n\n\ndef format_score_for_prompt(score_result, market_data):\n    lines = []\n    lines.append(f"RISK SCORE: {score_result[\'total_score\']}/{score_result[\'max_score\']}")\n    lines.append(f"LEVEL: {score_result[\'level_label\']}")\n    lines.append("")\n    lines.append("PILLAR BREAKDOWN:")\n    for p in score_result["pillars"]:\n        lines.append(f"  {p[\'icon\']} {p[\'name\']}: {p[\'score\']}/{p[\'max\']}")\n    lines.append("")\n    lines.append("ACTIVE CRISIS SIGNALS:")\n    if score_result["crisis_signals"]:\n        for s in score_result["crisis_signals"]:\n            lines.append(f"  ⚠️  [{s[\'pillar\']}] {s[\'name\']}: {s[\'description\']}")\n    else:\n        lines.append("  None — all signals clear")\n    lines.append("")\n    lines.append("KEY MARKET DATA:")\n    fields = [\n        ("IWM Price",              f"${market_data.get(\'iwm_price\', \'N/A\')}"),\n        ("1-Day Change",           f"{market_data.get(\'iwm_1d_chg_pct\', 0):+.2f}%"),\n        ("50-Day MA",              f"${market_data.get(\'ma50\', \'N/A\')}"),\n        ("200-Day MA",             f"${market_data.get(\'ma200\', \'N/A\')}"),\n        ("IWM vs 200MA",           f"{market_data.get(\'iwm_vs_200ma_pct\', 0):+.1f}%"),\n        ("RSI (14-day)",           f"{market_data.get(\'rsi14\', \'N/A\')}"),\n        ("VIX",                    f"{market_data.get(\'vix\', \'N/A\')}"),\n        ("HY Credit Spread",       f"{market_data.get(\'hy_spread\', \'N/A\')}%"),\n        ("Yield Curve (2-10yr)",   f"{market_data.get(\'yield_curve_spread\', 0):+.2f}%"),\n        ("ISM Manufacturing",      f"{market_data.get(\'ism_mfg\', \'N/A\')}"),\n        ("Jobless Claims (4wk)",   f"{market_data.get(\'jobless_claims_4wk\', \'N/A\')}k"),\n        ("S&P500 Breadth",         f"{market_data.get(\'sp500_pct_above_200ma\', \'N/A\')}% above 200MA"),\n        ("Golden Cross Active",    f"{\'YES\' if market_data.get(\'ma50\', 0) > market_data.get(\'ma200\', 0) else \'NO\'}"),\n    ]\n    for label, value in fields:\n        lines.append(f"  {label:<35} {value}")\n    return "\\n".join(lines)'

files["content_generator.py"] = '"""\ncontent_generator.py — Uses Claude API to generate all email content.\nThis is the core IP of Aperture+.\n"""\n\nimport anthropic\nimport json\nimport logging\nfrom datetime import datetime\nfrom config import ANTHROPIC_API_KEY, CLAUDE_MODEL, CLAUDE_MAX_TOKENS, BRAND_NAME, BRAND_WEBSITE\nfrom scorer import format_score_for_prompt\n\nlogger = logging.getLogger(__name__)\nclient = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)\n\nSYSTEM_PROMPT = """You are the senior macro analyst behind Aperture+, a daily market intelligence\nservice focused on IWM (Russell 2000 ETF) and US small cap markets. Website: aperture.plus\n\nYour readers are sophisticated self-directed investors, independent financial advisors, and\nsmall family offices managing $1M-$50M. They are smart, busy, and intolerant of vague content.\n\nVOICE RULES:\n- Write like a seasoned analyst who lived through 2008, 2020, and 2022\n- Be specific: always connect data points to DIRECT impact on IWM/small caps\n- Never use filler: "it\'s important to note", "as we can see", "interestingly"\n- Quantify everything: not "elevated" — say "VIX at 19.6, up from 17.8 last week"\n- Each insight must teach something they couldn\'t get from a Bloomberg headline\n- Confident without being arrogant. Cautious without being alarmist.\n\nCONTENT RULES:\n- Every claim must be grounded in the data provided. Do not invent statistics.\n- Always connect macro signals to Russell 2000 / small cap mechanism specifically\n- The Bottom Line must be a single decisive statement\n\nOUTPUT: Return valid JSON only. No markdown, no prose outside the JSON."""\n\n\ndef build_user_prompt(score_result, market_data, issue_number):\n    score_summary = format_score_for_prompt(score_result, market_data)\n    date_str = datetime.now().strftime("%A, %B %d, %Y")\n    return f"""Today is {date_str}. Issue #{issue_number}.\n\n{score_summary}\n\nGenerate the complete Aperture+ daily email content as JSON:\n\n{{\n  "subject_line": "Aperture+ — Score: X/16 | [compelling 5-word description]",\n  "verdict_headline": "2 sentences. Bold declarative statement about market state.",\n  "verdict_body": "2-3 sentences. Include 2 specific data points.",\n  "situation_paragraph": "3-4 sentences. Full picture with at least 3 specific numbers.",\n  "insights": [\n    {{\n      "number": 1,\n      "title": "Specific informative title",\n      "body": "3-4 sentences. Data point, mechanism, small cap impact, what to watch.",\n      "tag": "category | Bullish/Bearish/Watch"\n    }}\n  ],\n  "watch_today": [\n    {{\n      "time": "HH:MM EST",\n      "event": "Specific event name",\n      "why": "2 sentences: what it is and why it matters for IWM today",\n      "impact": "High Impact | Medium Impact | Technical Level | Fed Watch"\n    }}\n  ],\n  "be_careful": [\n    {{\n      "title": "Specific warning title",\n      "body": "3-4 sentences. Risk, mechanism, specific trigger level.",\n      "severity": "warning | danger"\n    }}\n  ],\n  "read_this": [\n    {{\n      "source": "Publication name",\n      "title": "Article title or topic",\n      "why": "1 sentence: why essential for IWM investors TODAY"\n    }}\n  ],\n  "bottom_line": "2 sentences. Most important takeaway. Score + specific level or event.",\n  "score_change_from_yesterday": 0\n}}\n\nReturn ONLY valid JSON."""\n\n\ndef generate_email_content(score_result, market_data, issue_number=1, prev_score=None):\n    logger.info("Generating content via Claude API...")\n    try:\n        message = client.messages.create(\n            model=CLAUDE_MODEL,\n            max_tokens=CLAUDE_MAX_TOKENS,\n            system=SYSTEM_PROMPT,\n            messages=[{"role": "user", "content": build_user_prompt(score_result, market_data, issue_number)}]\n        )\n        raw = message.content[0].text\n        content = json.loads(raw)\n        if prev_score is not None:\n            content["score_change_from_yesterday"] = score_result["total_score"] - prev_score\n        content["generated_at"] = datetime.now().isoformat()\n        logger.info(f"  ✓ Content generated")\n        return content\n    except json.JSONDecodeError as e:\n        logger.error(f"Claude returned invalid JSON: {e}")\n        return generate_fallback_content(score_result, market_data)\n    except Exception as e:\n        logger.error(f"Claude API error: {e}")\n        return generate_fallback_content(score_result, market_data)\n\n\ndef generate_fallback_content(score_result, market_data):\n    score = score_result["total_score"]\n    level = score_result["level_label"]\n    price = market_data.get("iwm_price", "N/A")\n    return {\n        "subject_line": f"Aperture+ — Score: {score}/16 | {level}",\n        "verdict_headline": f"Risk score: {score}/16. Market status: {level}.",\n        "verdict_body": f"IWM at ${price}.",\n        "situation_paragraph": "See signal table below for full breakdown.",\n        "insights": [{"number": 1, "title": f"Score: {score}/16", "body": f"IWM ${price}.", "tag": level}],\n        "watch_today": [],\n        "be_careful": [{"title": "Review signal table", "body": "See below.", "severity": "warning"}],\n        "read_this": [],\n        "bottom_line": f"Score: {score}/16. {level}.",\n        "score_change_from_yesterday": 0,\n        "generated_at": datetime.now().isoformat(),\n        "is_fallback": True,\n    }'

files["email_builder.py"] = '"""\nemail_builder.py — Assembles the final HTML email.\n"""\n\nimport logging\nfrom datetime import datetime\nfrom config import BRAND_NAME, BRAND_WEBSITE, SCORE_LEVELS\n\nlogger = logging.getLogger(__name__)\n\n\ndef get_score_color(score):\n    for level in SCORE_LEVELS:\n        if level[0] <= score <= level[1]:\n            return level[4]\n    return "#E05252"\n\n\ndef get_signal_display_value(signal_id, data):\n    mapping = {\n        "ma_depth":        f"{data.get(\'iwm_vs_200ma_pct\', 0):+.1f}% vs 200MA",\n        "death_cross":     f"50MA ${data.get(\'ma50\',\'?\')} vs 200MA ${data.get(\'ma200\',\'?\')}",\n        "ma200_direction": f"Slope: {\'Rising\' if data.get(\'ma200_slope\', 0) > 0 else \'Falling\'}",\n        "rsi":             f"RSI {data.get(\'rsi14\', \'N/A\')}",\n        "volume":          f"Vol ratio: {data.get(\'volume_ratio\', 1.0):.1f}x",\n        "breadth_200":     f"{data.get(\'sp500_pct_above_200ma\', \'N/A\')}% above 200MA",\n        "nh_nl":           f"NH: {data.get(\'new_highs\',\'?\')} / NL: {data.get(\'new_lows\',\'?\')}",\n        "ad_line":         f"A/D ratio: {data.get(\'advance_decline_ratio\', \'N/A\')}",\n        "sector_rotation": f"{\'Defensive leading\' if data.get(\'defensive_leading\') else \'Cyclicals leading\'}",\n        "yield_curve":     f"{data.get(\'yield_curve_spread\', 0):+.2f}% (2-10yr)",\n        "hy_spread":       f"{data.get(\'hy_spread\', \'N/A\')}%",\n        "ism":             f"{data.get(\'ism_mfg\', \'N/A\')}",\n        "jobless_claims":  f"{data.get(\'jobless_claims_4wk\', \'N/A\')}k",\n        "fed_policy":      f"{\'Hiking\' if data.get(\'fed_hiking\') else \'Pausing\'} @ {data.get(\'fed_funds_rate\',\'?\')}%",\n        "vix":             f"VIX {data.get(\'vix\', \'N/A\')}",\n        "put_call":        f"P/C ratio: {data.get(\'put_call_ratio\', \'N/A\')}",\n        "fund_flows":      f"{\'Risk-off\' if data.get(\'money_market_inflows\') else \'Risk-on\'}",\n    }\n    return mapping.get(signal_id, "N/A")\n\n\ndef build_email_html(content, score_result, market_data, issue_number):\n    score     = score_result["total_score"]\n    max_score = score_result["max_score"]\n    color     = get_score_color(score)\n    bar_width = round(score / max_score * 100, 1)\n    date_str  = datetime.now().strftime("%A, %B %d, %Y")\n    golden    = market_data.get("ma50", 0) > market_data.get("ma200", 0)\n    hy        = market_data.get("hy_spread", 0)\n    yc        = market_data.get("yield_curve_spread", 0)\n    iwm_chg   = market_data.get("iwm_1d_chg_pct", 0)\n\n    # Build signal rows\n    signal_rows = ""\n    for sig in score_result["signals"]:\n        dot = "red" if sig["is_crisis"] else "green"\n        val = get_signal_display_value(sig["id"], market_data)\n        status = sig["description"] if sig["is_crisis"] else "Clear"\n        signal_rows += f\'\'\'<tr>\n          <td style="padding:10px 12px;font-size:13px;border-bottom:1px solid #F0EBE3;color:#2A2A2A;font-weight:500">{sig["name"]}</td>\n          <td style="padding:10px 12px;font-size:12px;border-bottom:1px solid #F0EBE3;font-family:monospace;color:#555">{val}</td>\n          <td style="padding:10px 12px;font-size:12px;border-bottom:1px solid #F0EBE3">\n            <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:{\'#E05252\' if sig[\'is_crisis\'] else \'#3ECF8E\'};margin-right:6px"></span>\n            {status}\n          </td></tr>\'\'\'\n\n    # Build insights\n    insights_html = ""\n    for ins in content.get("insights", []):\n        insights_html += f\'\'\'<div style="display:flex;gap:16px;padding:16px 18px;background:#FDFAF4;border:1px solid #E5E0D5;border-left:3px solid #C9A84C;border-radius:0 4px 4px 0;margin-bottom:12px">\n          <div style="font-family:Georgia,serif;font-size:28px;font-weight:900;color:#E5E0D5;line-height:1;flex-shrink:0;width:28px">{ins["number"]}</div>\n          <div>\n            <div style="font-size:14px;font-weight:600;color:#0E0E0E;margin-bottom:5px">{ins["title"]}</div>\n            <div style="font-size:13px;color:#555;line-height:1.65">{ins["body"]}</div>\n            <span style="display:inline-block;font-size:9px;color:#999;background:#E5E0D5;padding:2px 7px;border-radius:2px;margin-top:6px;text-transform:uppercase;letter-spacing:0.06em">{ins.get("tag","")}</span>\n          </div></div>\'\'\'\n\n    # Build watch items\n    watch_html = ""\n    for w in content.get("watch_today", []):\n        watch_html += f\'\'\'<div style="background:#FDFAF4;border:1px solid #E5E0D5;border-radius:4px;padding:16px;margin-bottom:10px">\n          <div style="font-size:11px;color:#C9A84C;font-weight:500;margin-bottom:6px;font-family:monospace">{w["time"]}</div>\n          <div style="font-size:13px;font-weight:600;color:#0E0E0E;margin-bottom:5px">{w["event"]}</div>\n          <div style="font-size:12px;color:#777;line-height:1.55">{w["why"]}</div>\n        </div>\'\'\'\n\n    # Build warnings\n    careful_html = ""\n    for c in content.get("be_careful", []):\n        bg = "#FFF5F5" if c.get("severity") == "danger" else "#FFF8F0"\n        bc = "#E05252" if c.get("severity") == "danger" else "#E07B39"\n        careful_html += f\'\'\'<div style="background:{bg};border:1px solid {bc}40;border-left:4px solid {bc};border-radius:0 4px 4px 0;padding:20px 22px;margin-bottom:14px">\n          <div style="font-size:14px;font-weight:600;color:{bc};margin-bottom:10px">{"🔴" if c.get("severity")=="danger" else "⚠️"} {c["title"]}</div>\n          <div style="font-size:13px;color:#555;line-height:1.65">{c["body"]}</div>\n        </div>\'\'\'\n\n    # Build read this\n    read_html = ""\n    for r in content.get("read_this", []):\n        read_html += f\'\'\'<div style="display:flex;gap:14px;padding:14px 16px;background:#FDFAF4;border:1px solid #E5E0D5;border-radius:4px;margin-bottom:8px">\n          <div style="flex:1">\n            <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px">{r["source"]}</div>\n            <div style="font-size:13px;font-weight:600;color:#0E0E0E;margin-bottom:4px">{r["title"]}</div>\n            <div style="font-size:12px;color:#777">{r["why"]}</div>\n          </div>\n          <div style="font-size:16px;color:#C9A84C">→</div>\n        </div>\'\'\'\n\n    # Build pillar cards\n    pillars_html = ""\n    status_colors = {"clear": "#3ECF8E", "warn": "#C9A84C", "danger": "#E05252"}\n    for p in score_result["pillars"]:\n        c = status_colors.get(p["status"], "#3ECF8E")\n        pillars_html += f\'\'\'<div style="background:#1E1E1E;border:1px solid #2A2A2A;border-radius:4px;padding:12px;text-align:center;border-left:3px solid {c}">\n          <div style="font-size:18px;margin-bottom:6px">{p["icon"]}</div>\n          <div style="font-size:10px;color:#666;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.05em">{p["name"]}</div>\n          <div style="font-size:18px;font-weight:500;color:{c};font-family:monospace">{p["score"]}<span style="font-size:11px;color:#444">/{p["max"]}</span></div>\n        </div>\'\'\'\n\n    iwm_chg_str = f"{\'▲\' if iwm_chg >= 0 else \'▼\'} {abs(iwm_chg):.2f}% yesterday"\n    iwm_chg_color = "#3ECF8E" if iwm_chg >= 0 else "#E05252"\n\n    html = f"""<!DOCTYPE html>\n<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">\n<title>Aperture+ — {date_str}</title></head>\n<body style="margin:0;padding:0;background:#F5F2EC;font-family:\'DM Sans\',Arial,sans-serif;color:#1A1A1A">\n<div style="max-width:680px;margin:0 auto;background:#F5F2EC">\n\n  <!-- HEADER -->\n  <div style="background:#0E0E0E;padding:28px 40px 24px;border-bottom:3px solid #C9A84C;display:flex;justify-content:space-between;align-items:center">\n    <div style="font-size:28px;font-weight:900;color:#F5F2EC;letter-spacing:-0.5px">Aperture<span style="color:#C9A84C">+</span></div>\n    <div>\n      <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:0.1em">{date_str}</div>\n      <div style="font-size:10px;color:#555;text-transform:uppercase;letter-spacing:0.08em">Daily Intelligence · Issue #{issue_number}</div>\n    </div>\n  </div>\n\n  <!-- SCORE HERO -->\n  <div style="background:#0E0E0E;padding:32px 40px 36px">\n    <div style="display:flex;align-items:flex-start;gap:32px">\n      <div>\n        <div style="font-size:10px;color:#888;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:6px">Risk Score</div>\n        <div style="font-size:72px;font-weight:900;line-height:1;color:{color}">{score}</div>\n        <div style="font-size:16px;color:#555;margin-top:4px;font-family:monospace">/ {max_score}</div>\n      </div>\n      <div style="padding-top:4px;border-left:2px solid #2A2A2A;padding-left:32px;flex:1">\n        <div style="display:inline-block;background:{color}22;border:1px solid {color};color:{color};font-size:11px;text-transform:uppercase;padding:4px 12px;border-radius:2px;margin-bottom:12px;letter-spacing:0.1em">{score_result["level_label"]}</div>\n        <div style="font-size:22px;font-weight:700;color:#F5F2EC;line-height:1.3;margin-bottom:10px">{content.get("verdict_headline","")}</div>\n        <div style="font-size:13px;color:#999;line-height:1.7">{content.get("verdict_body","")}</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- SCORE BAR -->\n  <div style="background:#161616;padding:16px 40px;border-bottom:1px solid #2A2A2A">\n    <div style="background:#2A2A2A;border-radius:3px;height:6px;position:relative;overflow:hidden">\n      <div style="height:100%;border-radius:3px;background:linear-gradient(90deg,#3ECF8E,#C9A84C 50%,#E05252);width:{bar_width}%"></div>\n    </div>\n    <div style="display:flex;justify-content:space-between;margin-top:8px">\n      <span style="font-size:9px;color:#555;text-transform:uppercase;letter-spacing:0.08em">0 Clear</span>\n      <span style="font-size:9px;color:#555;text-transform:uppercase;letter-spacing:0.08em">4 Watch</span>\n      <span style="font-size:9px;color:#555;text-transform:uppercase;letter-spacing:0.08em">9 Reduce</span>\n      <span style="font-size:9px;color:#555;text-transform:uppercase;letter-spacing:0.08em">13 Exit</span>\n      <span style="font-size:9px;color:#555;text-transform:uppercase;letter-spacing:0.08em">16 Crisis</span>\n    </div>\n  </div>\n\n  <!-- PILLARS -->\n  <div style="background:#161616;padding:24px 40px;border-bottom:1px solid #2A2A2A">\n    <div style="font-size:10px;color:#555;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:16px">Score Breakdown</div>\n    <div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:10px">{pillars_html}</div>\n  </div>\n\n  <!-- CONTENT BODY -->\n  <div style="background:#F5F2EC">\n\n    <!-- SNAPSHOT -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px;letter-spacing:0.08em">01</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Market Snapshot</span>\n      </div>\n      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:1px;background:#E5E0D5;border:1px solid #E5E0D5;border-radius:4px;overflow:hidden;margin-bottom:20px">\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">IWM (Russell 2000)</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">${market_data.get("iwm_price","N/A")}</div>\n          <div style="font-size:11px;color:{iwm_chg_color};margin-top:3px">{iwm_chg_str}</div>\n        </div>\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">200-Day MA</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">${market_data.get("ma200","N/A")}</div>\n          <div style="font-size:11px;color:#3ECF8E;margin-top:3px">+{market_data.get("iwm_vs_200ma_pct",0):.1f}% above</div>\n        </div>\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">50-Day MA</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">${market_data.get("ma50","N/A")}</div>\n          <div style="font-size:11px;color:{"#3ECF8E" if golden else "#E05252"};margin-top:3px">{"Golden Cross ✓" if golden else "Death Cross ⚠"}</div>\n        </div>\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">VIX</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">{market_data.get("vix","N/A")}</div>\n          <div style="font-size:11px;color:#999;margin-top:3px">{"↑ Rising" if market_data.get("vix_trend",0) > 1 else "→ Stable"}</div>\n        </div>\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">HY Credit Spread</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">{hy}%</div>\n          <div style="font-size:11px;color:#3ECF8E;margin-top:3px">Tight — Low stress</div>\n        </div>\n        <div style="background:#FDFAF4;padding:16px 18px">\n          <div style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px">Yield Curve</div>\n          <div style="font-size:18px;font-weight:500;color:#0E0E0E;font-family:monospace">{"+" if yc >= 0 else ""}{yc:.2f}%</div>\n          <div style="font-size:11px;color:{"#3ECF8E" if yc > 0 else "#E05252"};margin-top:3px">{"Normal" if yc > 0 else "⚠ INVERTED"}</div>\n        </div>\n      </div>\n      <p style="font-size:15px;line-height:1.85;color:#2A2A2A">{content.get("situation_paragraph","")}</p>\n    </div>\n\n    <!-- INSIGHTS -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px">02</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Top 5 Insights</span>\n      </div>\n      {insights_html}\n    </div>\n\n    <!-- WATCH TODAY -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px">03</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Watch Today</span>\n      </div>\n      {watch_html}\n    </div>\n\n    <!-- BE CAREFUL -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px">04</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Be Careful About This</span>\n      </div>\n      {careful_html}\n    </div>\n\n    <!-- READ THIS -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px">05</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Read This Today</span>\n      </div>\n      {read_html}\n    </div>\n\n    <!-- SIGNAL TABLE -->\n    <div style="padding:32px 40px;border-bottom:1px solid #E5E0D5">\n      <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">\n        <span style="font-size:11px;color:#C9A84C;background:#C9A84C15;border:1px solid #C9A84C40;padding:3px 8px;border-radius:2px">06</span>\n        <span style="font-size:20px;font-weight:700;color:#0E0E0E">Full Signal Status</span>\n      </div>\n      <table style="width:100%;border-collapse:collapse">\n        <thead><tr>\n          <th style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;padding:8px 12px;text-align:left;border-bottom:1px solid #E5E0D5;background:#FAF7F1">Signal</th>\n          <th style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;padding:8px 12px;text-align:left;border-bottom:1px solid #E5E0D5;background:#FAF7F1">Reading</th>\n          <th style="font-size:9px;color:#999;text-transform:uppercase;letter-spacing:0.1em;padding:8px 12px;text-align:left;border-bottom:1px solid #E5E0D5;background:#FAF7F1">Status</th>\n        </tr></thead>\n        <tbody>{signal_rows}</tbody>\n      </table>\n    </div>\n\n  </div>\n\n  <!-- BOTTOM LINE -->\n  <div style="background:#0E0E0E;padding:28px 40px">\n    <div style="font-size:10px;color:#555;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:10px">The Bottom Line</div>\n    <div style="font-size:18px;color:#F5F2EC;line-height:1.6;font-style:italic">{content.get("bottom_line","")}</div>\n  </div>\n\n  <!-- FOOTER -->\n  <div style="background:#0A0A0A;padding:24px 40px;border-top:1px solid #1E1E1E">\n    <div style="font-size:16px;font-weight:700;color:#F5F2EC">Aperture<span style="color:#C9A84C">+</span></div>\n    <div style="font-size:11px;color:#444;line-height:1.6;margin-top:16px">\n      Aperture+ is an automated market intelligence service. All content is generated by algorithmic\n      analysis and AI synthesis of publicly available market data. This is not investment advice.\n      Aperture+ does not manage money, hold licenses as a financial advisor, or make recommendations\n      to buy or sell any security. Always consult a licensed financial advisor before making investment decisions.\n    </div>\n    <div style="margin-top:12px;font-size:10px;color:#333">\n      aperture.plus · <a href="{{{{unsubscribe_url}}}}" style="color:#555;text-decoration:none">Unsubscribe</a>\n    </div>\n  </div>\n\n</div></body></html>"""\n\n    return html'

files["social_poster.py"] = '"""\nsocial_poster.py — Posts to Twitter/X, Instagram, LinkedIn automatically.\n"""\n\nimport os, requests, logging\nfrom datetime import datetime\n\nlogger = logging.getLogger(__name__)\n\nTWITTER_API_KEY      = os.getenv("TWITTER_API_KEY")\nTWITTER_API_SECRET   = os.getenv("TWITTER_API_SECRET")\nTWITTER_ACCESS_TOKEN = os.getenv("TWITTER_ACCESS_TOKEN")\nTWITTER_ACCESS_SECRET= os.getenv("TWITTER_ACCESS_SECRET")\nTWITTER_BEARER_TOKEN = os.getenv("TWITTER_BEARER_TOKEN")\nBUFFER_TOKEN         = os.getenv("BUFFER_ACCESS_TOKEN")\nBUFFER_INSTAGRAM_ID  = os.getenv("BUFFER_INSTAGRAM_PROFILE_ID")\nBUFFER_LINKEDIN_ID   = os.getenv("BUFFER_LINKEDIN_PROFILE_ID")\nSIGNAL_WEBSITE       = os.getenv("SIGNAL_WEBSITE", "https://aperture.plus")\n\n\ndef post_twitter_thread(score_result, content, market_data):\n    try:\n        import tweepy\n        client = tweepy.Client(\n            bearer_token=TWITTER_BEARER_TOKEN,\n            consumer_key=TWITTER_API_KEY, consumer_secret=TWITTER_API_SECRET,\n            access_token=TWITTER_ACCESS_TOKEN, access_token_secret=TWITTER_ACCESS_SECRET,\n        )\n        score = score_result["total_score"]\n        level = score_result["level_label"]\n        iwm   = market_data.get("iwm_price","N/A")\n        vix   = market_data.get("vix","N/A")\n        hy    = market_data.get("hy_spread","N/A")\n        emoji = "🟢" if score<=4 else "🟡" if score<=8 else "🟠" if score<=12 else "🔴"\n        date  = datetime.now().strftime("%b %d")\n\n        t1 = f"""{emoji} Aperture+ Risk Score: {score}/16 — {level}\n\n{date} snapshot:\n• IWM: ${iwm}\n• 200MA: ${market_data.get("ma200","N/A")} ({market_data.get("iwm_vs_200ma_pct",0):+.1f}% above)\n• VIX: {vix}\n• HY Spread: {hy}%\n\n{score_result["level_action"]}\n\n🧵"""\n\n        top = content.get("insights",[{}])[0]\n        t2 = f"""📊 Top insight today:\n\n{top.get("title","")}\n\n{top.get("body","")[:220]}..."""\n\n        warn = content.get("be_careful",[{}])[0]\n        t3 = f"""⚠️ Be careful:\n\n{warn.get("title","")}\n\n{warn.get("body","")[:200]}..."""\n\n        t4 = f"""📬 Full Aperture+ analysis:\n• 5 insights · Key events · 16-signal breakdown\n\nFree trial → {SIGNAL_WEBSITE}\n\n#IWM #Russell2000 #investing #markets"""\n\n        r1 = client.create_tweet(text=t1)\n        tid = r1.data["id"]\n        r2 = client.create_tweet(text=t2, in_reply_to_tweet_id=tid)\n        tid = r2.data["id"]\n        r3 = client.create_tweet(text=t3, in_reply_to_tweet_id=tid)\n        tid = r3.data["id"]\n        client.create_tweet(text=t4, in_reply_to_tweet_id=tid)\n\n        logger.info("  ✓ Twitter thread posted")\n        return True\n    except Exception as e:\n        logger.error(f"Twitter failed: {e}")\n        return False\n\n\ndef build_instagram_caption(score_result, content, market_data):\n    score = score_result["total_score"]\n    level = score_result["level_label"]\n    date  = datetime.now().strftime("%B %d, %Y")\n    opening = "✅" if score<=4 else "🟡" if score<=8 else "🟠" if score<=12 else "🔴"\n    insights = content.get("insights",[])\n    lines = "".join([f"\n{i+1}. {ins[\'title\']}" for i, ins in enumerate(insights[:3])])\n    bl = content.get("bottom_line","")[:180]\n    return f"""{opening} Aperture+ Risk Score: {score}/16 — {level}\n{date}\n\nToday\'s top insights:{lines}\n\nBottom line: {bl}\n\n─────────────────\n💡 Save this — scores change daily\n📬 Full analysis → link in bio (aperture.plus)\n─────────────────\n#IWM #Russell2000 #StockMarket #Investing #Finance #MarketAnalysis #TechnicalAnalysis #FinancialEducation #WealthManagement #Stocks #Trading #SmallCap #MacroEconomics"""\n\n\ndef post_instagram_carousel(image_paths, caption):\n    if not BUFFER_TOKEN or not BUFFER_INSTAGRAM_ID:\n        logger.warning("Buffer credentials not set.")\n        return False\n    headers = {"Authorization": f"Bearer {BUFFER_TOKEN}"}\n    media_ids = []\n    for path in image_paths[:10]:\n        try:\n            with open(path,"rb") as f:\n                r = requests.post("https://api.bufferapp.com/1/media/upload.json",\n                    headers={"Authorization": f"Bearer {BUFFER_TOKEN}"},\n                    files={"file": (path.split("/")[-1], f, "image/png")})\n                r.raise_for_status()\n                mid = r.json().get("id")\n                if mid: media_ids.append(mid)\n        except Exception as e:\n            logger.error(f"Buffer upload failed: {e}")\n    if not media_ids:\n        return False\n    try:\n        r = requests.post("https://api.bufferapp.com/1/updates/create.json",\n            headers=headers,\n            json={"profile_ids":[BUFFER_INSTAGRAM_ID],"text":caption,\n                  "media":{"photo_ids":media_ids},"now":True})\n        r.raise_for_status()\n        logger.info(f"  ✓ Instagram carousel posted ({len(media_ids)} slides)")\n        return True\n    except Exception as e:\n        logger.error(f"Buffer Instagram failed: {e}")\n        return False\n\n\ndef post_linkedin(score_result, content, market_data):\n    if not BUFFER_TOKEN or not BUFFER_LINKEDIN_ID:\n        return False\n    score = score_result["total_score"]\n    level = score_result["level_label"]\n    date  = datetime.now().strftime("%B %d, %Y")\n    top   = content.get("insights",[{}])[0]\n    bl    = content.get("bottom_line","")\n    text  = f"""Aperture+ Daily Intelligence — {date}\n\nRisk Score: {score}/16 ({level})\nIWM: ${market_data.get("iwm_price","N/A")}\n\nKey insight: {top.get("title","")}\n{top.get("body","")[:300]}\n\nBottom line: {bl}\n\nNot investment advice. aperture.plus\n\n#Finance #Investing #MarketAnalysis #IWM"""\n    try:\n        r = requests.post("https://api.bufferapp.com/1/updates/create.json",\n            headers={"Authorization": f"Bearer {BUFFER_TOKEN}"},\n            json={"profile_ids":[BUFFER_LINKEDIN_ID],"text":text,"now":True})\n        r.raise_for_status()\n        logger.info("  ✓ LinkedIn posted")\n        return True\n    except Exception as e:\n        logger.error(f"LinkedIn failed: {e}")\n        return False\n\n\ndef post_all_social(score_result, content, market_data, carousel_paths, dry_run=False):\n    if dry_run:\n        logger.info("  ⚡ DRY RUN — social not posted")\n        return {}\n    results = {}\n    logger.info("  Posting to social...")\n    results["twitter"]   = post_twitter_thread(score_result, content, market_data)\n    caption = build_instagram_caption(score_result, content, market_data)\n    results["instagram"] = post_instagram_carousel(carousel_paths, caption)\n    results["linkedin"]  = post_linkedin(score_result, content, market_data)\n    logger.info(f"  ✓ Social complete: {sum(1 for v in results.values() if v)}/{len(results)} platforms")\n    return results'

files["sender.py"] = '"""\nsender.py — Sends email via Beehiiv API.\n"""\n\nimport requests, logging\nfrom datetime import datetime\nfrom config import BEEHIIV_API_KEY, BEEHIIV_PUB_ID\n\nlogger = logging.getLogger(__name__)\nBEEHIIV_BASE = "https://api.beehiiv.com/v2"\n\n\ndef create_and_send_post(subject, html_content, score, issue_number, send_to="both", test_mode=False):\n    headers = {"Authorization": f"Bearer {BEEHIIV_API_KEY}", "Content-Type": "application/json"}\n    post_data = {\n        "subject_line": subject,\n        "preview_text": f"Risk Score: {score}/16 · {datetime.now().strftime(\'%B %d, %Y\')}",\n        "content_html": html_content,\n        "status": "draft",\n    }\n    try:\n        r = requests.post(f"{BEEHIIV_BASE}/publications/{BEEHIIV_PUB_ID}/posts",\n                         json=post_data, headers=headers, timeout=30)\n        r.raise_for_status()\n        post_id = r.json()["data"]["id"]\n        logger.info(f"  ✓ Post created: {post_id}")\n        if test_mode:\n            return {"status": "draft", "post_id": post_id}\n        r = requests.post(f"{BEEHIIV_BASE}/publications/{BEEHIIV_PUB_ID}/posts/{post_id}/publish",\n                         json={"send_at": None, "audience": "free"}, headers=headers, timeout=30)\n        r.raise_for_status()\n        logger.info("  ✓ Email sent!")\n        return r.json()\n    except Exception as e:\n        logger.error(f"Beehiiv failed: {e}")\n        raise\n\n\ndef send_test_email(html_content, subject, test_email):\n    headers = {"Authorization": f"Bearer {BEEHIIV_API_KEY}", "Content-Type": "application/json"}\n    try:\n        r = requests.post(f"{BEEHIIV_BASE}/publications/{BEEHIIV_PUB_ID}/posts",\n                         json={"subject_line": subject, "content_html": html_content, "status": "draft"},\n                         headers=headers, timeout=30)\n        r.raise_for_status()\n        post_id = r.json()["data"]["id"]\n        r = requests.post(f"{BEEHIIV_BASE}/publications/{BEEHIIV_PUB_ID}/posts/{post_id}/send_test",\n                         json={"email": test_email}, headers=headers, timeout=30)\n        r.raise_for_status()\n        logger.info(f"  ✓ Test email sent to {test_email}")\n        return True\n    except Exception as e:\n        logger.error(f"Test email failed: {e}")\n        return False\n\n\ndef get_subscriber_count():\n    headers = {"Authorization": f"Bearer {BEEHIIV_API_KEY}"}\n    try:\n        r = requests.get(f"{BEEHIIV_BASE}/publications/{BEEHIIV_PUB_ID}/subscriptions",\n                        headers=headers, params={"limit": 1}, timeout=10)\n        r.raise_for_status()\n        return {"total": r.json().get("total_results", 0)}\n    except Exception as e:\n        logger.error(f"Subscriber count failed: {e}")\n        return {"total": 0}'

files["scheduler.py"] = '"""\nscheduler.py — Master controller for Aperture+\n\nUsage:\n  python scheduler.py           # Start daily scheduler (6am ET, weekdays)\n  python scheduler.py --dry-run # Run pipeline, print output, don\'t send\n  python scheduler.py --test    # Run once, send test email to TEST_EMAIL\n  python scheduler.py --send    # Run once and send to all subscribers\n"""\n\nimport os, sys, json, logging, argparse, schedule, time\nfrom datetime import datetime\nfrom pathlib import Path\n\nPath("logs").mkdir(exist_ok=True)\nlogging.basicConfig(\n    level=logging.INFO,\n    format="%(asctime)s  %(levelname)-8s  %(message)s",\n    datefmt="%H:%M:%S",\n    handlers=[logging.StreamHandler(), logging.FileHandler("logs/aperture.log")]\n)\nlogger = logging.getLogger(__name__)\n\nfrom config import SEND_TIME, BRAND_NAME\nfrom data_fetcher import fetch_all_market_data\nfrom scorer import calculate_score\nfrom content_generator import generate_email_content\nfrom email_builder import build_email_html\nfrom carousel_generator import generate_carousel\nfrom social_poster import post_all_social, build_instagram_caption\nfrom sender import create_and_send_post, send_test_email, get_subscriber_count\n\nSTATE_FILE = "logs/state.json"\n\ndef load_state():\n    if Path(STATE_FILE).exists():\n        with open(STATE_FILE) as f: return json.load(f)\n    return {"issue_number": 1, "last_score": None, "last_run": None}\n\ndef save_state(state):\n    with open(STATE_FILE, "w") as f: json.dump(state, f, indent=2)\n\n\ndef run_pipeline(send=False, test_email=None, dry_run=False):\n    state        = load_state()\n    issue_number = state["issue_number"]\n    prev_score   = state.get("last_score")\n    today        = datetime.now()\n\n    logger.info(f"\\n{\'=\'*60}")\n    logger.info(f"  Aperture+ Pipeline — Issue #{issue_number}")\n    logger.info(f"  {today.strftime(\'%A, %B %d, %Y %H:%M:%S ET\')}")\n    logger.info(f"{\'=\'*60}\\n")\n\n    # STEP 1: Fetch Data\n    logger.info("STEP 1: Fetching market data")\n    market_data = fetch_all_market_data()\n    logger.info(f"  IWM: ${market_data.get(\'iwm_price\')} | VIX: {market_data.get(\'vix\')}\\n")\n\n    # STEP 2: Score\n    logger.info("STEP 2: Calculating risk score")\n    score_result = calculate_score(market_data)\n    score        = score_result["total_score"]\n    logger.info(f"  ── SCORE: {score}/16 — {score_result[\'level_label\']} ──\\n")\n\n    # STEP 3: Generate Content\n    logger.info("STEP 3: Generating content via Claude API")\n    content = generate_email_content(score_result, market_data, issue_number, prev_score)\n    logger.info(f"  Subject: {content.get(\'subject_line\')}\\n")\n\n    # STEP 4: Build Email\n    logger.info("STEP 4: Building HTML email")\n    html = build_email_html(content, score_result, market_data, issue_number)\n    archive_path = f"logs/email_{issue_number:04d}_{today.strftime(\'%Y%m%d\')}.html"\n    with open(archive_path, "w") as f: f.write(html)\n    with open(f"logs/content_{issue_number:04d}.json", "w") as f:\n        json.dump({"issue": issue_number, "score": score, "content": content,\n                   "market_data": {k:v for k,v in market_data.items()\n                                   if not callable(v)}}, f, indent=2)\n    logger.info(f"  ✓ Saved to {archive_path}\\n")\n\n    # STEP 5: Generate Carousel\n    logger.info("STEP 5: Generating carousel slides")\n    carousel_dir  = f"logs/carousel_{today.strftime(\'%Y%m%d\')}"\n    carousel_data = {\n        "score":       score,\n        "date":        today.strftime("%A, %B %d, %Y"),\n        "verdict":     content.get("verdict_headline",""),\n        "bottom_line": content.get("bottom_line",""),\n        "key_levels": [\n            f"IWM 200MA: ${market_data.get(\'ma200\')} — primary support",\n            f"IWM 50MA: ${market_data.get(\'ma50\')} — must hold",\n            f"VIX >25 = re-score trigger",\n        ],\n        "market_data": market_data,\n        "pillars":     score_result["pillars"],\n        "insights":    content.get("insights",[]),\n    }\n    carousel_paths = generate_carousel(carousel_data, carousel_dir)\n    logger.info(f"  ✓ {len(carousel_paths)} slides generated\\n")\n\n    if dry_run:\n        logger.info("  ⚡ DRY RUN complete — nothing sent")\n        logger.info(f"  Email: {archive_path}")\n        logger.info(f"  Carousel: {carousel_dir}/")\n        return\n\n    subject = content.get("subject_line", f"Aperture+ — Score: {score}/16")\n\n    # STEP 6: Send Email\n    logger.info("STEP 6: Sending email")\n    if test_email:\n        send_test_email(html, subject, test_email)\n    elif send:\n        subs = get_subscriber_count()\n        logger.info(f"  Sending to {subs.get(\'total\',\'?\')} subscribers")\n        create_and_send_post(subject, html, score, issue_number, test_mode=False)\n\n        # STEP 7: Social\n        logger.info("\\nSTEP 7: Posting to social media")\n        caption = build_instagram_caption(score_result, content, market_data)\n        post_all_social(score_result, content, market_data, carousel_paths)\n\n        state.update({"issue_number": issue_number+1, "last_score": score,\n                      "last_run": today.isoformat()})\n        save_state(state)\n\n    logger.info(f"\\n{\'=\'*60}")\n    logger.info(f"  ✅ Complete — Issue #{issue_number} — Score: {score}/16")\n    logger.info(f"{\'=\'*60}\\n")\n\n\ndef start_scheduler():\n    logger.info(f"Aperture+ Scheduler — daily at {SEND_TIME} ET (weekdays only)")\n    for day in ["monday","tuesday","wednesday","thursday","friday"]:\n        getattr(schedule.every(), day).at(SEND_TIME).do(lambda: run_pipeline(send=True))\n    logger.info(f"Next run: {schedule.next_run()}")\n    while True:\n        schedule.run_pending()\n        time.sleep(60)\n\n\nif __name__ == "__main__":\n    parser = argparse.ArgumentParser(description="Aperture+ Daily Pipeline")\n    parser.add_argument("--test",    action="store_true")\n    parser.add_argument("--send",    action="store_true")\n    parser.add_argument("--dry-run", action="store_true", dest="dry_run")\n    args = parser.parse_args()\n\n    if args.test:\n        email = os.getenv("TEST_EMAIL","")\n        if not email:\n            print("Set TEST_EMAIL in .env first")\n            sys.exit(1)\n        run_pipeline(test_email=email)\n    elif args.send:\n        run_pipeline(send=True)\n    elif args.dry_run:\n        run_pipeline(dry_run=True)\n    else:\n        start_scheduler()'

files["carousel_generator.py"] = '"""\nSignal. Instagram Carousel Generator\nProduces 8 slides (1080x1080px) ready for Instagram, LinkedIn, TikTok slideshow\n"""\n\nfrom PIL import Image, ImageDraw, ImageFont\nimport os, textwrap, math\n\n# ── PATHS ──────────────────────────────────────────────────────────────────\nFONTS = {\n    \'serif\':      \'/usr/share/fonts/truetype/google-fonts/Lora-Variable.ttf\',\n    \'bold\':       \'/usr/share/fonts/truetype/google-fonts/Poppins-Bold.ttf\',\n    \'medium\':     \'/usr/share/fonts/truetype/google-fonts/Poppins-Medium.ttf\',\n    \'regular\':    \'/usr/share/fonts/truetype/google-fonts/Poppins-Regular.ttf\',\n    \'mono\':       \'/usr/share/fonts/truetype/dejavu/DejaVuSansMono.ttf\',\n}\n\n# ── PALETTE ────────────────────────────────────────────────────────────────\nC = {\n    \'bg\':        \'#0A0A0F\',\n    \'bg2\':       \'#12121A\',\n    \'gold\':      \'#C9A84C\',\n    \'gold_dim\':  \'#8B6F2E\',\n    \'green\':     \'#3ECF8E\',\n    \'red\':       \'#E05252\',\n    \'orange\':    \'#E07B39\',\n    \'white\':     \'#F0EDE6\',\n    \'grey1\':     \'#8A8A9A\',\n    \'grey2\':     \'#3A3A4A\',\n    \'grey3\':     \'#1E1E2A\',\n}\n\nW, H = 1080, 1080\nPAD = 72\n\ndef font(name, size):\n    return ImageFont.truetype(FONTS[name], size)\n\ndef hex_to_rgb(h):\n    h = h.lstrip(\'#\')\n    return tuple(int(h[i:i+2], 16) for i in (0, 2, 4))\n\ndef score_color(score):\n    if score <= 4:  return C[\'green\']\n    if score <= 8:  return C[\'gold\']\n    if score <= 12: return C[\'orange\']\n    return C[\'red\']\n\ndef score_label(score):\n    if score <= 4:  return "LOW RISK"\n    if score <= 8:  return "ELEVATED"\n    if score <= 12: return "HIGH RISK"\n    return "CRISIS"\n\ndef new_canvas():\n    img = Image.new(\'RGB\', (W, H), C[\'bg\'])\n    draw = ImageDraw.Draw(img)\n    return img, draw\n\ndef draw_gradient_bar(draw, x, y, w, h, score, max_score=16):\n    """Horizontal score progress bar with gradient fill"""\n    # Track\n    draw.rounded_rectangle([x, y, x+w, y+h], radius=h//2, fill=C[\'grey3\'])\n    # Fill\n    fill_w = int((score / max_score) * w)\n    if fill_w > h:\n        color = score_color(score)\n        draw.rounded_rectangle([x, y, x+fill_w, y+h], radius=h//2, fill=color)\n    # Tick marks\n    for tick_score, label in [(4,\'\'), (8,\'\'), (12,\'\')]:\n        tx = x + int((tick_score / max_score) * w)\n        draw.rectangle([tx-1, y-4, tx+1, y+h+4], fill=C[\'grey2\'])\n\ndef draw_noise_texture(draw, alpha=12):\n    """Subtle grain texture for depth"""\n    import random\n    random.seed(42)\n    for _ in range(8000):\n        x = random.randint(0, W)\n        y = random.randint(0, H)\n        v = random.randint(180, 255)\n        a = random.randint(0, alpha)\n        draw.point([x, y], fill=(v, v, v))\n\ndef draw_brand(draw, slide_num, total=8):\n    """Top bar: brand + slide counter"""\n    # Brand\n    f = font(\'bold\', 28)\n    draw.text((PAD, 44), "SIGNAL", font=f, fill=C[\'gold\'])\n    draw.text((PAD + 108, 44), ".", font=f, fill=C[\'white\'])\n    \n    # Slide counter dots\n    dot_r = 5\n    dot_spacing = 18\n    total_w = (total - 1) * dot_spacing + dot_r * 2\n    start_x = W - PAD - total_w\n    for i in range(total):\n        cx = start_x + i * dot_spacing + dot_r\n        cy = 58\n        if i == slide_num - 1:\n            draw.ellipse([cx-dot_r, cy-dot_r, cx+dot_r, cy+dot_r], fill=C[\'gold\'])\n        else:\n            draw.ellipse([cx-dot_r+1, cy-dot_r+1, cx+dot_r-1, cy+dot_r-1], \n                        outline=C[\'grey2\'], fill=None)\n\ndef draw_bottom_cta(draw, text="swipe for insights →"):\n    """Bottom CTA"""\n    f = font(\'medium\', 22)\n    bbox = draw.textbbox((0,0), text, font=f)\n    tw = bbox[2] - bbox[0]\n    draw.text(((W - tw) // 2, H - 56), text, font=f, fill=C[\'grey1\'])\n\ndef wrap_text(text, max_chars):\n    """Wrap text to max chars per line"""\n    return textwrap.wrap(text, width=max_chars)\n\ndef draw_multiline(draw, lines, x, y, fnt, fill, line_height=None):\n    """Draw multiple lines, return final y position"""\n    if line_height is None:\n        bbox = draw.textbbox((0,0), "Ag", font=fnt)\n        line_height = int((bbox[3] - bbox[1]) * 1.45)\n    for line in lines:\n        draw.text((x, y), line, font=fnt, fill=fill)\n        y += line_height\n    return y\n\n# ────────────────────────────────────────────────────────────────────────────\n# SLIDE GENERATORS\n# ────────────────────────────────────────────────────────────────────────────\n\ndef slide_1_score_reveal(data):\n    """THE HOOK — Big score reveal"""\n    img, draw = new_canvas()\n    draw_noise_texture(draw, 8)\n    \n    score = data[\'score\']\n    color = score_color(score)\n    label = score_label(score)\n    date  = data[\'date\']\n    \n    # Subtle radial glow behind score\n    for r in range(220, 0, -20):\n        alpha = int(18 * (1 - r/220))\n        rgb = hex_to_rgb(color)\n        glow_color = f\'#{rgb[0]:02x}{rgb[1]:02x}{rgb[2]:02x}\'\n        draw.ellipse([W//2 - r, 380 - r, W//2 + r, 380 + r], \n                    fill=None, outline=glow_color)\n    \n    draw_brand(draw, 1)\n    \n    # Date\n    f_date = font(\'regular\', 24)\n    draw.text((PAD, 120), date.upper(), font=f_date, fill=C[\'grey1\'])\n    \n    # "TODAY\'S RISK SCORE"\n    f_label = font(\'medium\', 26)\n    label_text = "TODAY\'S RISK SCORE"\n    bbox = draw.textbbox((0,0), label_text, font=f_label)\n    lw = bbox[2] - bbox[0]\n    draw.text(((W - lw)//2, 240), label_text, font=f_label, fill=C[\'grey1\'])\n    \n    # BIG NUMBER\n    f_score = font(\'bold\', 220)\n    score_str = str(score)\n    bbox = draw.textbbox((0,0), score_str, font=f_score)\n    sw = bbox[2] - bbox[0]\n    draw.text(((W - sw)//2, 270), score_str, font=f_score, fill=color)\n    \n    # "/16"\n    f_max = font(\'regular\', 52)\n    max_str = "/ 16"\n    bbox = draw.textbbox((0,0), max_str, font=f_max)\n    mw = bbox[2] - bbox[0]\n    draw.text(((W - mw)//2, 530), max_str, font=f_max, fill=C[\'grey1\'])\n    \n    # Score bar\n    draw_gradient_bar(draw, PAD, 640, W - PAD*2, 12, score)\n    \n    # Labels under bar\n    f_bar = font(\'regular\', 18)\n    for val, lbl in [(0,\'CLEAR\'), (4,\'WATCH\'), (8,\'REDUCE\'), (12,\'EXIT\'), (16,\'CRISIS\')]:\n        bx = PAD + int((val/16) * (W - PAD*2))\n        bbox = draw.textbbox((0,0), lbl, font=f_bar)\n        bw = bbox[2] - bbox[0]\n        draw.text((bx - bw//2, 666), lbl, font=f_bar, fill=C[\'grey2\'])\n    \n    # Status badge\n    badge_w, badge_h = 220, 52\n    bx = (W - badge_w) // 2\n    by = 730\n    draw.rounded_rectangle([bx, by, bx+badge_w, by+badge_h], radius=8, fill=C[\'grey3\'])\n    draw.rounded_rectangle([bx, by, bx+badge_w, by+badge_h], radius=8, outline=color, width=2)\n    f_badge = font(\'bold\', 22)\n    bbox = draw.textbbox((0,0), label, font=f_badge)\n    lw = bbox[2] - bbox[0]\n    draw.text(((W - lw)//2, by + 14), label, font=f_badge, fill=color)\n    \n    # Verdict (1 line)\n    verdict = data.get(\'verdict\', \'Markets hold above all key levels.\')\n    f_v = font(\'regular\', 30)\n    lines = wrap_text(verdict, 36)[:2]\n    y = 830\n    for line in lines:\n        bbox = draw.textbbox((0,0), line, font=f_v)\n        lw = bbox[2] - bbox[0]\n        draw.text(((W - lw)//2, y), line, font=f_v, fill=C[\'white\'])\n        y += 44\n    \n    draw_bottom_cta(draw, "swipe to see what\'s driving this  →")\n    return img\n\n\ndef slide_2_pillars(data):\n    """4 PILLAR BREAKDOWN"""\n    img, draw = new_canvas()\n    draw_noise_texture(draw, 6)\n    draw_brand(draw, 2)\n    \n    # Title\n    f_title = font(\'bold\', 44)\n    draw.text((PAD, 118), "Score Breakdown", font=f_title, fill=C[\'white\'])\n    \n    f_sub = font(\'regular\', 26)\n    draw.text((PAD, 174), "4 pillars · 16 signals total", font=f_sub, fill=C[\'grey1\'])\n    \n    # Horizontal divider\n    draw.rectangle([PAD, 218, W-PAD, 220], fill=C[\'grey3\'])\n    \n    pillars = data[\'pillars\']  # list of {name, icon, score, max, status}\n    \n    card_w = (W - PAD*2 - 20) // 2\n    card_h = 200\n    \n    positions = [\n        (PAD, 250),\n        (PAD + card_w + 20, 250),\n        (PAD, 470),\n        (PAD + card_w + 20, 470),\n    ]\n    \n    status_colors = {\'clear\': C[\'green\'], \'warn\': C[\'gold\'], \'danger\': C[\'red\']}\n    \n    for i, (pillar, (px, py)) in enumerate(zip(pillars, positions)):\n        color = status_colors.get(pillar[\'status\'], C[\'grey1\'])\n        \n        # Card background\n        draw.rounded_rectangle([px, py, px+card_w, py+card_h], radius=12, fill=C[\'grey3\'])\n        # Left accent bar\n        draw.rounded_rectangle([px, py, px+4, py+card_h], radius=2, fill=color)\n        \n        # Icon + Name\n        f_icon = font(\'bold\', 36)\n        draw.text((px+22, py+20), pillar[\'icon\'], font=f_icon, fill=C[\'white\'])\n        \n        f_name = font(\'medium\', 22)\n        draw.text((px+22, py+66), pillar[\'name\'].upper(), font=f_name, fill=C[\'grey1\'])\n        \n        # Score\n        score_str = f"{pillar[\'score\']}"\n        max_str = f"/{pillar[\'max\']}"\n        \n        f_ps = font(\'bold\', 64)\n        f_pm = font(\'regular\', 28)\n        \n        bbox = draw.textbbox((0,0), score_str, font=f_ps)\n        sw = bbox[2] - bbox[0]\n        draw.text((px+22, py+98), score_str, font=f_ps, fill=color)\n        draw.text((px+22+sw+4, py+122), max_str, font=f_pm, fill=C[\'grey1\'])\n        \n        # Mini bar\n        bar_x = px + 22\n        bar_y = py + 174\n        bar_w = card_w - 44\n        draw.rounded_rectangle([bar_x, bar_y, bar_x+bar_w, bar_y+8], \n                               radius=4, fill=C[\'grey2\'])\n        fill_w = int((pillar[\'score\'] / pillar[\'max\']) * bar_w) if pillar[\'max\'] else 0\n        if fill_w > 4:\n            draw.rounded_rectangle([bar_x, bar_y, bar_x+fill_w, bar_y+8], \n                                   radius=4, fill=color)\n    \n    # Bottom summary\n    score = data[\'score\']\n    color = score_color(score)\n    f_sum = font(\'medium\', 28)\n    summary = f"Total: {score}/16 · {score_label(score)}"\n    bbox = draw.textbbox((0,0), summary, font=f_sum)\n    sw = bbox[2] - bbox[0]\n    draw.text(((W-sw)//2, 710), summary, font=f_sum, fill=color)\n    \n    # Key insight teaser\n    f_teaser = font(\'regular\', 26)\n    teaser = "Swipe to see today\'s top 5 market insights"\n    bbox = draw.textbbox((0,0), teaser, font=f_teaser)\n    tw = bbox[2] - bbox[0]\n    draw.text(((W-tw)//2, 762), teaser, font=f_teaser, fill=C[\'grey1\'])\n    \n    draw_bottom_cta(draw)\n    return img\n\n\ndef slide_insight(data, insight_index, slide_num):\n    """INSIGHT SLIDE (slides 3-7)"""\n    img, draw = new_canvas()\n    draw_noise_texture(draw, 6)\n    draw_brand(draw, slide_num)\n    \n    insights = data[\'insights\']\n    if insight_index >= len(insights):\n        return None\n    \n    ins = insights[insight_index]\n    num = insight_index + 1\n    \n    # Big insight number (decorative)\n    f_bignum = font(\'bold\', 180)\n    draw.text((W - 160, 80), str(num), font=f_bignum, fill=C[\'grey3\'])\n    \n    # "INSIGHT #N" label\n    f_label = font(\'medium\', 22)\n    label = f"INSIGHT  {num} OF 5"\n    draw.text((PAD, 120), label, font=f_label, fill=C[\'gold\'])\n    \n    # Gold accent line\n    draw.rectangle([PAD, 158, PAD+60, 163], fill=C[\'gold\'])\n    \n    # Title\n    f_title = font(\'bold\', 42)\n    title_lines = wrap_text(ins[\'title\'], 28)[:3]\n    y = 188\n    for line in title_lines:\n        draw.text((PAD, y), line, font=f_title, fill=C[\'white\'])\n        y += 56\n    \n    y += 16  # gap\n    \n    # Divider\n    draw.rectangle([PAD, y, W-PAD, y+2], fill=C[\'grey3\'])\n    y += 24\n    \n    # Body text\n    f_body = font(\'regular\', 28)\n    body_lines = wrap_text(ins[\'body\'], 38)[:7]\n    for line in body_lines:\n        draw.text((PAD, y), line, font=f_body, fill=C[\'grey1\'])\n        y += 44\n    \n    y += 20\n    \n    # Tag pill\n    tag = ins.get(\'tag\', \'\').split(\'|\')[0].strip().upper()\n    if tag:\n        f_tag = font(\'medium\', 20)\n        bbox = draw.textbbox((0,0), tag, font=f_tag)\n        tw = bbox[2] - bbox[0]\n        pill_pad = 16\n        pill_w = tw + pill_pad * 2\n        pill_h = 36\n        draw.rounded_rectangle([PAD, y, PAD+pill_w, y+pill_h], \n                               radius=pill_h//2, fill=C[\'grey3\'])\n        draw.text((PAD+pill_pad, y+8), tag, font=f_tag, fill=C[\'gold\'])\n    \n    # Score reminder (bottom right)\n    score = data[\'score\']\n    color = score_color(score)\n    f_score_sm = font(\'bold\', 32)\n    score_str = f"{score}/16"\n    bbox = draw.textbbox((0,0), score_str, font=f_score_sm)\n    sw = bbox[2] - bbox[0]\n    draw.text((W - PAD - sw, H - 100), score_str, font=f_score_sm, fill=color)\n    f_score_lbl = font(\'regular\', 20)\n    lbl = "risk score"\n    bbox = draw.textbbox((0,0), lbl, font=f_score_lbl)\n    lw = bbox[2] - bbox[0]\n    draw.text((W - PAD - lw, H - 64), lbl, font=f_score_lbl, fill=C[\'grey1\'])\n    \n    if insight_index < 4:\n        draw_bottom_cta(draw, f"insight {num+1} of 5  →")\n    else:\n        draw_bottom_cta(draw, "swipe for the bottom line  →")\n    \n    return img\n\n\ndef slide_8_bottom_line(data):\n    """FINAL SLIDE — Bottom line + CTA"""\n    img, draw = new_canvas()\n    draw_noise_texture(draw, 8)\n    draw_brand(draw, 8)\n    \n    score = data[\'score\']\n    color = score_color(score)\n    \n    # "THE BOTTOM LINE"\n    f_label = font(\'medium\', 26)\n    draw.text((PAD, 120), "THE BOTTOM LINE", font=f_label, fill=C[\'gold\'])\n    draw.rectangle([PAD, 158, W-PAD, 161], fill=C[\'grey3\'])\n    \n    # Bottom line text (large, impactful)\n    f_bl = font(\'serif\', 46)\n    bl_text = data.get(\'bottom_line\', f\'Score: {score}/16. Stay alert.\')\n    lines = wrap_text(bl_text, 26)[:5]\n    y = 190\n    for line in lines:\n        draw.text((PAD, y), line, font=f_bl, fill=C[\'white\'])\n        y += 64\n    \n    y += 30\n    \n    # Key levels box\n    draw.rounded_rectangle([PAD, y, W-PAD, y+160], radius=12, fill=C[\'grey3\'])\n    draw.rounded_rectangle([PAD, y, W-PAD, y+160], radius=12, outline=color, width=2)\n    \n    f_kl_title = font(\'medium\', 22)\n    draw.text((PAD+24, y+18), "KEY LEVELS TO WATCH", font=f_kl_title, fill=color)\n    \n    f_kl = font(\'regular\', 26)\n    levels = data.get(\'key_levels\', [\n        f"IWM 200MA: ${data[\'market_data\'].get(\'ma200\', 221)}",\n        f"IWM 50MA: ${data[\'market_data\'].get(\'ma50\', 244)}",\n        f"VIX: {data[\'market_data\'].get(\'vix\', 19.6)} (watch >25)"\n    ])\n    ky = y + 52\n    for lvl in levels[:3]:\n        draw.text((PAD+24, ky), f"→  {lvl}", font=f_kl, fill=C[\'white\'])\n        ky += 36\n    \n    y += 200\n    \n    # CTA box\n    cta_y = y\n    draw.rounded_rectangle([PAD, cta_y, W-PAD, cta_y+130], radius=14, fill=color)\n    \n    f_cta1 = font(\'bold\', 30)\n    cta1 = "Get the full daily analysis"\n    bbox = draw.textbbox((0,0), cta1, font=f_cta1)\n    cw = bbox[2] - bbox[0]\n    draw.text(((W-cw)//2, cta_y+18), cta1, font=f_cta1, fill=C[\'bg\'])\n    \n    f_cta2 = font(\'medium\', 24)\n    cta2 = "signal-intelligence.com"\n    bbox = draw.textbbox((0,0), cta2, font=f_cta2)\n    cw = bbox[2] - bbox[0]\n    draw.text(((W-cw)//2, cta_y+60), cta2, font=f_cta2, fill=C[\'bg\'])\n    \n    f_cta3 = font(\'regular\', 20)\n    cta3 = "Link in bio  ·  Free trial available"\n    bbox = draw.textbbox((0,0), cta3, font=f_cta3)\n    cw = bbox[2] - bbox[0]\n    draw.text(((W-cw)//2, cta_y+96), cta3, font=f_cta3, fill=C[\'bg\'])\n    \n    return img\n\n\n# ── MAIN FUNCTION ─────────────────────────────────────────────────────────\n\ndef generate_carousel(data: dict, output_dir: str = \'/tmp/carousel\') -> list[str]:\n    """\n    Generate all 8 carousel slides.\n    \n    data dict needs:\n      score, date, verdict, bottom_line, pillars, insights, market_data\n    \n    Returns list of file paths.\n    """\n    os.makedirs(output_dir, exist_ok=True)\n    paths = []\n    \n    slides = [\n        (\'01_score_reveal\',   slide_1_score_reveal(data)),\n        (\'02_pillars\',        slide_2_pillars(data)),\n        (\'03_insight_1\',      slide_insight(data, 0, 3)),\n        (\'04_insight_2\',      slide_insight(data, 1, 4)),\n        (\'05_insight_3\',      slide_insight(data, 2, 5)),\n        (\'06_insight_4\',      slide_insight(data, 3, 6)),\n        (\'07_insight_5\',      slide_insight(data, 4, 7)),\n        (\'08_bottom_line\',    slide_8_bottom_line(data)),\n    ]\n    \n    for name, img in slides:\n        if img is None:\n            continue\n        path = os.path.join(output_dir, f\'signal_{name}.png\')\n        img.save(path, \'PNG\', quality=95)\n        paths.append(path)\n        print(f"  ✓ {name}")\n    \n    return paths\n\n\n# ── TEST DATA ─────────────────────────────────────────────────────────────\n\nif __name__ == \'__main__\':\n    test_data = {\n        \'score\': 2,\n        \'date\': \'Friday, February 27, 2026\',\n        \'verdict\': \'Markets hold firm above all key levels. No crisis signal active.\',\n        \'bottom_line\': \'Score 2/16. Golden Cross intact, credit markets calm. Watch PCE today and ISM on March 2. Bias remains: stay invested.\',\n        \'key_levels\': [\n            \'IWM 200MA: $221 — primary support\',\n            \'IWM 50MA: $244 — must hold on pullback\',\n            \'VIX >25 = re-score trigger\',\n        ],\n        \'market_data\': {\n            \'iwm_price\': 264.28,\n            \'ma50\': 243.95,\n            \'ma200\': 221.23,\n            \'vix\': 19.62,\n            \'hy_spread\': 2.95,\n            \'yield_curve_spread\': 0.60,\n            \'iwm_vs_200ma_pct\': 19.5,\n        },\n        \'pillars\': [\n            {\'name\': \'Technical\',  \'icon\': \'📊\', \'score\': 0, \'max\': 5, \'status\': \'clear\'},\n            {\'name\': \'Breadth\',    \'icon\': \'🌊\', \'score\': 0, \'max\': 4, \'status\': \'clear\'},\n            {\'name\': \'Macro\',      \'icon\': \'🏛\', \'score\': 1, \'max\': 5, \'status\': \'warn\'},\n            {\'name\': \'Sentiment\',  \'icon\': \'🧠\', \'score\': 1, \'max\': 4, \'status\': \'warn\'},\n        ],\n        \'insights\': [\n            {\n                \'title\': "ISM\'s 52.6 reading is a genuine turning point",\n                \'body\': "After 26 consecutive months of contraction, US manufacturing expanded in January — the longest drought since 2008-09. New orders jumped to 57.1, highest since Feb 2022. Small caps are the primary beneficiary when manufacturing turns: 77% of Russell 2000 revenue is domestic.",\n                \'tag\': \'Manufacturing · Bullish for IWM\',\n            },\n            {\n                \'title\': \'Golden Cross intact — but watch momentum\',\n                \'body\': "The 50-day MA ($244) remains above the 200-day MA ($221). Every sustained IWM bull run occurred with Golden Cross active. One caveat: momentum indicators softened even as price held. Divergence (strong price, weakening momentum) is a yellow flag for the next 2-3 weeks.",\n                \'tag\': \'Technical · Watch\',\n            },\n            {\n                \'title\': \'Credit markets are the cleanest all-clear signal\',\n                \'body\': "High yield spreads at 2.95% are near 5-year tights. The corporate bond market is pricing essentially zero financial stress. In every major IWM crisis, HY spreads blew out to 500-800bps BEFORE stocks cracked. Current spreads say: no systemic risk on the horizon.",\n                \'tag\': \'Credit · Very Bullish\',\n            },\n            {\n                \'title\': \'The Warsh transition is the one unknown\',\n                \'body\': "Kevin Warsh replaces Powell in May 2026. As a \\"sound money\\" advocate he may be less dovish. Small caps carry 32% floating-rate debt vs 6% for large caps. A hawkish surprise from new Fed chair could disproportionately hit Russell 2000. Tail risk, not base case.",\n                \'tag\': \'Fed Policy · Tail Risk\',\n            },\n            {\n                \'title\': \'Tariff noise is back — market has learned to discount it\',\n                \'body\': "Supreme Court struck IEEPA tariffs, Trump responded with 10% blanket tariff. IWM barely moved. Compare to April 2025 when tariff shock sent IWM down 25%. Reduced sensitivity suggests risk is partially priced in — but sector-specific escalation could still sting.",\n                \'tag\': \'Trade Policy · Priced In\',\n            },\n        ],\n    }\n\n    print("\\nGenerating Signal. carousel slides...\\n")\n    paths = generate_carousel(test_data, \'/tmp/carousel\')\n    print(f"\\n✓ {len(paths)} slides generated")\n    for p in paths:\n        size = os.path.getsize(p) // 1024\n        print(f"  {os.path.basename(p)}  ({size}KB)")'


for filename, content in files.items():
    with open(filename, 'w') as f:
        f.write(content)
    print(f"✓ Created {filename}")

